// AppLogger.kt
// Centralized logging utility to ensure consistent log formatting and tagging.
import timber.log.Timber

object AppLogger {

    private const val TAG_AUTH = "AppAuth"
    private const val TAG_DB = "AppDB"
    private const val TAG_API = "AppAPI"
    private const val TAG_EXCEPTION = "AppException"

    fun logAuthAttempt(username: String, success: Boolean, message: String? = null) {
        val status = if (success) "SUCCESS" else "FAILED"
        val logMessage = "Authentication attempt for user '$username': $status. ${message ?: ""}"
        if (success) {
            Timber.tag(TAG_AUTH).i(logMessage)
        } else {
            Timber.tag(TAG_AUTH).w(logMessage)
        }
    }

    fun logDatabaseQuery(query: String, params: Map<String, Any>?) {
        val formattedParams = params?.entries?.joinToString(separator = ", ") { "${it.key}=${it.value}" } ?: "No parameters"
        Timber.tag(TAG_DB).v("Executing DB Query: '$query' with parameters: {$formattedParams}")
    }

    fun logApiRequest(
        method: String,
        url: String,
        headers: Map<String, String>?,
        requestBody: String?
    ) {
        val headerString = headers?.entries?.joinToString { "${it.key}: ${it.value}" } ?: "No headers"
        val bodyString = requestBody ?: "No request body"
        Timber.tag(TAG_API).v(
            "API Request: %s %s\nHeaders: %s\nBody: %s",
            method, url, headerString, bodyString
        )
    }

    fun logApiResponse(
        url: String,
        responseCode: Int,
        responseHeaders: Map<String, String>?,
        responseBody: String?
    ) {
        val headerString = responseHeaders?.entries?.joinToString { "${it.key}: ${it.value}" } ?: "No headers"
        val bodyString = responseBody ?: "No response body"
        Timber.tag(TAG_API).v(
            "API Response for %s\nCode: %d\nHeaders: %s\nBody: %s",
            url, responseCode, headerString, bodyString
        )
    }

    fun logApiError(
        url: String,
        error: Throwable,
        requestBody: String? = null
    ) {
        val bodyString = requestBody ?: "N/A"
        Timber.tag(TAG_API).e(error, "API Error for %s\nRequest Body: %s", url, bodyString)
    }

    fun logException(throwable: Throwable, message: String? = null) {
        Timber.tag(TAG_EXCEPTION).e(throwable, message ?: "An unexpected error occurred.")
    }
}


// LoggingInterceptor.kt
// An OkHttp Interceptor to automatically log API requests and responses.
import okhttp3.Interceptor
import okhttp3.Response
import okio.Buffer
import java.io.IOException
import java.nio.charset.Charset
import java.util.concurrent.TimeUnit

class LoggingInterceptor : Interceptor {

    @Throws(IOException::class)
    override fun intercept(chain: Interceptor.Chain): Response {
        val request = chain.request()

        val requestStartTime = System.nanoTime()

        // Log Request
        val requestMethod = request.method
        val requestUrl = request.url.toString()
        val requestHeaders = request.headers.toMap()
        var requestBody: String? = null

        request.body?.let { body ->
            val buffer = Buffer()
            body.writeTo(buffer)
            // Clone the request body buffer to avoid consuming the stream for the actual request
            requestBody = buffer.readString(Charset.forName("UTF-8"))
        }

        AppLogger.logApiRequest(requestMethod, requestUrl, requestHeaders, requestBody)

        val response: Response
        try {
            response = chain.proceed(request)
        } catch (e: Exception) {
            AppLogger.logApiError(requestUrl, e, requestBody)
            throw e
        }

        val responseEndTime = System.nanoTime()
        val duration = TimeUnit.NANOSECONDS.toMillis(responseEndTime - requestStartTime)

        // Log Response
        val responseCode = response.code
        val responseHeaders = response.headers.toMap()
        var responseBody: String? = null

        response.body?.let { body ->
            val contentLength = body.contentLength()
            if (contentLength != 0L) { // Only read if there's content
                // Ensure the response body is not consumed for the actual client
                val source = body.source()
                source.request(Long.MAX_VALUE) // Buffer the entire body
                val buffer = source.buffer
                responseBody = buffer.clone().readString(Charset.forName("UTF-8"))
            }
        }

        AppLogger.logApiResponse(requestUrl, responseCode, responseHeaders, responseBody)
        return response
    }
}

